from llama_stack.client import LlamaStack
from vex_sdk import verify

def detect_safety_false_positive(response):
    if hasattr(response, 'safety_shield') and response.safety_shield.blocked:
        # Check if content is actually benign
        verdict = verify({
            'safety_false_positive': {
                'content': response.content,
                'blocked_reason': response.safety_shield.reason
            }
        })
        return verdict.issues
    return None

from llama_stack.agents import AgentLoop

def detect_loop_exhaustion(loop_state):
    if loop_state.turn_count >= loop_state.max_turns:
        resolution_score = len(loop_state.final_answer or '') / 100
        if resolution_score < 0.3:
            return {
                'issue': 'LOOP_EXHAUSTED',
                'turns_used': loop_state.turn_count,
                'has_resolution': bool(loop_state.final_answer)
            }
    return None

from pydantic import ValidationError
from llama_stack.tools import ToolResponse

def detect_tool_schema_failure(tool_response):
    try:
        validated = ToolResponse.model_validate(tool_response.raw)
        return None
    except ValidationError as e:
        return {
            'issue': 'TOOL_SCHEMA_FAILURE',
            'field_errors': [f.field for f in e.errors()],
            'raw_response': tool_response.raw
        }

