from llama_stack.client import LlamaStack
from vex_sdk import verify

stack = LlamaStack()
response = stack.chat("Analyze Q3 earnings")

if response.safety_shield.blocked:
    # Vex double-checks safety
    safety_verdict = verify({
        'llama_safety_override': {
            'content': response.content,
            'original_block': response.safety_shield.reason
        }
    })

    if not safety_verdict.issues:
        response.safety_shield.blocked = False
        print('Safety override approved by Vex')

stack.respond(response)

from llama_stack.agents import AgentLoop

def smart_loop_extension(loop: AgentLoop):
    if loop.turn_count >= loop.max_turns * 0.8:
        progress = analyze_progress(loop.state_history)
        if progress.momentum > 0.6:
            loop.max_turns += 5
            print(f'Extended loop to {loop.max_turns} turns')
    return loop

def analyze_progress(history):
    # Simple momentum calculation
    recent_quality = [h.quality_score for h in history[-3:]]
    return {'momentum': sum(recent_quality)/len(recent_quality)}

import json
from llama_stack.tools import ToolResponse

def repair_tool_response(raw_response):
    if isinstance(raw_response, str):
        try:
            # Try JSON parsing first
            parsed = json.loads(raw_response)
        except:
            # Fallback: wrap string in minimal schema
            parsed = {'content': raw_response, 'success': True}

        return ToolResponse.model_validate(parsed)
    return ToolResponse.model_validate(raw_response)

